写这个解析器主要是为了看自己的 C++ 水平，毕竟 JSON 是一个同时能做到语法简单的同时考验人的编码水平的 data structure，其次是为了好玩。 好玩吗？好玩。 结构 ¶ 我们使用 https://www.json.org/json-en.html 作为解析的依据。因为是个玩具，这个解析器不打算遵循任何标准。 一个 JSON 的“值” 分为六种可能，也就是 Null: null, 空值 Boolean: 布尔值 Number: 数字 String: 字符串 Array: 数组 Object: key-value 映射 其中 Array 和 Object 又会存放任何可能的 JSON 值。 由于 C++ 显然会比较难写，先来看一下 Rust 大概会怎么写。 enum JSONNode { Null, Bool(bool), Number(i64), String(String), Array(Vec&lt;JSONNode&gt;), Object(HashMap&lt;String, JSONNode&gt;), } fn parse(sv: &amp;str) -&gt; Result&lt;JSONNode, String&gt; { let sv = sv.trim_start(); if let Some(first) = sv.chars().nth(0) { match first { 'n' =&gt; Ok(parseNull(sv)), 't' =&gt; Ok(parseBool(sv)), 'f' =&gt; Ok(parseBool(sv)), '&quot;' =&gt; Ok(parseString(sv)), '0'..'9' =&gt; Ok(parseNumber(sv)), '{' =&gt; Ok(parseObject(sv)), '[' =&gt; Ok(parseArray(sv)), _ =&gt; Err(format!(&quot;unexpected token {first}&quot;)) } } else { Err(&quot;expect json value&quot;.to_string()) } } ⬆️ 好了也就是看一下而已。但是对于 C++ 我们没有好的 enum，如果要写得比较方便而不是追求性能的话就要用到虚函数和虚继承。 首先定义一个节点的可能性： enum class NodeType { Null, Boolean, Number, String, Array, Object, }; JSON 中不会出现不属于上面六类“值”，因此“值”应该是一个虚基类，包含一些纯虚函数 class Node { public: inline static std::unique_ptr&lt;Node&gt; parse(std::string_view &amp;sv, int dep) { assert_depth(sv, dep); removeWhiteSpaces(sv); switch (sv[0]) { case 'n': return Null::parse(sv); case 't': case 'f': return Boolean::parse(sv); case '{': return Object::parse(sv, dep + 1); // 控制递归深度，防止溢出 case '[': return Array::parse(sv, dep + 1); // 同上 case '&quot;': return String::parse(sv); case '-': case '0' ... '9': return Number::parse(sv); default: throw getJSONParseError(sv, &quot;any JSON value&quot;); } }; virtual inline NodeType getType() const noexcept = 0; template &lt;class T&gt; requires std::is_base_of_v&lt;Node, T&gt; inline T &amp;cast() noexcept { return *(static_cast&lt;T *&gt;(this)); } template &lt;class T&gt; requires std::is_base_of_v&lt;Node, T&gt; inline const T &amp;cast() const noexcept { return *(static_cast&lt;const T *&gt;(this)); } virtual inline std::string dump() const { switch (this-&gt;getType()) { case NodeType::Null: return this-&gt;cast&lt;Null&gt;().dump(); case NodeType::Boolean: return this-&gt;cast&lt;Boolean&gt;().dump(); case NodeType::Number: return this-&gt;cast&lt;Number&gt;().dump(); case NodeType::String: return this-&gt;cast&lt;String&gt;().dump(); case NodeType::Array: return this-&gt;cast&lt;Array&gt;().dump(); case NodeType::Object: return this-&gt;cast&lt;Object&gt;().dump(); } throw JSONException(&quot;unreachable: a JSON::Node has no nodetype&quot;); }; virtual ~Node() {}; }; 一个节点显然最好是独占其资源的所有权的，所以返回一个 std::unique_ptr&lt;Node&gt;，帮我们免除手动释放内存的烦恼。 因为是指针，可以简单的 cast 到子类，调用子类的方法。 而一个 JSON 对象什么其它的都不存，只存放这个 std::unique_ptr&lt;Node&gt;，作为一个 unique_ptr&lt;Node&gt; 的包装器而存在。 Parse ¶ null, boolean, number, string 的解析比较显然，略 array 和 object 有共通性，这里只解释比较复杂的 object class Object : public Node { using ObjectVT = std::unordered_map&lt;std::string, JSON&gt;; ObjectVT value_{}; public: Object() {}; explicit Object(ObjectVT &amp;&amp;val) : value_(std::move(val)) {}; Object(Object &amp;&amp;) = default; Object(const Object &amp;) = delete; // 删掉拷贝构造函数 （虽然本来就被 JSON 删了） Object &amp;operator=(Object &amp;&amp;) = default; Object &amp;operator=(const Object &amp;) = delete; inline static std::unique_ptr&lt;Object&gt; parse(std::string_view &amp;sv, int dep) { assert_depth(sv, dep); removeWhiteSpaces(sv); if (sv[0] != '{') throw getJSONParseError(sv, &quot;object start `{`&quot;); sv.remove_prefix(1); removeWhiteSpaces(sv); ObjectVT val; bool isTComma = false; // 是不是尾随逗号 while (sv[0] != '}') { auto key = String::parse(sv); // 解析 key if (ENABLE_DUMPLICATED_KEY_DETECT &amp;&amp; val.contains(key-&gt;value())) { throw getJSONParseError( sv, (&quot;unique key, but got dumplicated key `&quot; + key-&gt;value() + &quot;`&quot;) .c_str()); } else { removeWhiteSpaces(sv); if (sv[0] != ':') // 解析 key : throw getJSONParseError(sv, &quot;object spliter `:`&quot;); sv.remove_prefix(1); val.insert({key-&gt;take(), JSON(Node::parse(sv, dep + 1))}); removeWhiteSpaces(sv); // 解析 key : value switch (sv[0]) { case '}': // 看看结束了没 sv.remove_prefix(1); return std::make_unique&lt;Object&gt;(std::move(val)); case ',': sv.remove_prefix(1); isTComma = true; continue; default: throw getJSONParseError(sv, &quot;object spliter `,` or object end `}`&quot;); } } } if (isTComma &amp;&amp; !ENABLE_TRAILING_COMMA) throw getJSONParseError(sv, &quot;next json value&quot;); sv.remove_prefix(1); return std::make_unique&lt;Object&gt;(std::move(val)); } inline NodeType getType() const noexcept override { return NodeType::Object; } inline std::string dump() const override { std::string s = &quot;{&quot;; for (const auto &amp;[key, val] : value_) { s += String::toJSONString(key); s += &quot;:&quot;; s += val-&gt;dump(); s += &quot;,&quot;; } if (!value_.empty()) s.pop_back(); s += '}'; return s; } JSON &amp;operator[](const std::string &amp;s) { return value_[s]; } const JSON &amp;operator[](const std::string &amp;s) const { return value_[s]; } }; 多么简单呐（赞赏）只需要用 general 的 Node::parse 解析 object 里面的任意 value，将得到的 value node 移动进自己的 unordered_map (hash map) 就写完了！ 想必看完上面的代码和注释大家都懂了吧（跑路） 因此整个 json 的 parser 就非常好写了： static JSON parse(std::string_view sv) { auto res = Node::parse(sv, 0); removeWhiteSpaces(sv); if (!sv.empty()) { throw getJSONParseError(sv, &quot;EOF&quot;); // 希望整个 json 只有一个 root node } return JSON(std::move(res)); } 为了方便使用…… ¶ 现在雏形已经出来了，但是每个 JSON 必须要显式用 make_unique 构造，以至于你会看到类似这样的蠢蠢的语法： json[&quot;some_key&quot;] = std::make_unique&lt;JSON::Boolean&gt;(false); 怎么将它简化呢？ class JSON { public: JSON() : _uptr(std::make_unique&lt;Null&gt;()) {}; // 一个 JSON 默认应该是个 null JSON(JSON &amp;&amp;) = default; template &lt;typename T&gt; requires std::is_base_of_v&lt;Node, T&gt; explicit JSON(std::unique_ptr&lt;T&gt; &amp;&amp;uptr) : _uptr(std::move(uptr)) {} // 用unique ptr构造 JSON &amp;operator=(JSON &amp;&amp;) = default; JSON &amp;operator=(const JSON &amp;) = delete; inline JSON &amp;operator=(std::unique_ptr&lt;Node&gt; &amp;&amp;uptr) { _uptr = std::move(uptr); return *this; } template &lt;typename T&gt; requires std::is_base_of_v&lt;Node, T&gt; explicit JSON(T &amp;&amp;node) : _uptr(std::make_unique&lt;T&gt;(std::forward&lt;T&gt;(node))) {} // 用 value 的类构造 template &lt;typename T&gt; requires std::is_base_of_v&lt;Node, T&gt; inline JSON &amp;operator=(T &amp;&amp;node) { _uptr = std::make_unique&lt;T&gt;(std::forward&lt;T&gt;(node)); return *this; } explicit JSON(std::nullptr_t) : JSON() {} inline JSON &amp;operator=(std::nullptr_t) { // 用 nullptr 赋值 _uptr = std::make_unique&lt;Null&gt;(); return *this; } explicit JSON(bool boolean) : _uptr(std::make_unique&lt;Boolean&gt;(boolean)) {} inline JSON &amp;operator=(bool boolean) { // 用 bool 赋值 _uptr = std::make_unique&lt;Boolean&gt;(boolean); return *this; } template &lt;typename IntN&gt; requires std::numeric_limits&lt;IntN&gt;::is_integer explicit JSON(IntN integer) : _uptr(std::make_unique&lt;Number&gt;(static_cast&lt;int64_t&gt;(integer))) {} template &lt;typename IntN&gt; requires std::numeric_limits&lt;IntN&gt;::is_integer inline JSON &amp;operator=(IntN integer) { // 用看上去是 integer 的任何类型赋值 _uptr = std::make_unique&lt;Number&gt;(static_cast&lt;int64_t&gt;(integer)); return *this; } explicit JSON(double float_number) : _uptr(std::make_unique&lt;Number&gt;(float_number)) {} inline JSON &amp;operator=(double float_number) { // 用 浮点数 赋值 _uptr = std::make_unique&lt;Number&gt;(float_number); return *this; } explicit JSON(std::string str) : _uptr(std::make_unique&lt;String&gt;(std::move(str))) {} inline JSON &amp;operator=(std::string str) { // 用 string 赋值（因为总是要复制一遍的，不妨直接用 std::string 然后 move 进去 _uptr = std::make_unique&lt;String&gt;(std::move(str)); return *this; } explicit JSON(const char *c_str) : _uptr(std::make_unique&lt;String&gt;(c_str)) {} inline JSON &amp;operator=(const char *c_str) { // 用 C 风格 string 赋值 _uptr = std::make_unique&lt;String&gt;(c_str); return *this; } std::unique_ptr&lt;Node&gt; &amp;operator-&gt;() { return _uptr; } // 重载 -&gt; const std::unique_ptr&lt;Node&gt; &amp;operator-&gt;() const { return _uptr; } } 多么简单呐（赞赏） 特别的，为了方便写 Array，我们写个 makeArray，用万能引用确保东西原样转发进去： static void pushArray_(Array &amp;) {} template &lt;typename T&gt; static void pushArray_(Array &amp;arr, T &amp;&amp;t) { arr.value_.emplace_back(JSON(std::forward&lt;T&gt;(t))); } template &lt;typename T, typename... Args&gt; static void pushArray_(Array &amp;arr, T &amp;&amp;t, Args &amp;&amp;...args) { arr.value_.emplace_back(JSON(std::forward&lt;T&gt;(t))); pushArray_(arr, std::forward&lt;Args&gt;(args)...); } template &lt;typename... Args&gt; static Array makeArray(Args &amp;&amp;...args) { Array res; pushArray_(res, std::forward&lt;Args&gt;(args)...); return res; } 现在你可以这样 dump 一个 JSON 了 JSON json{std::make_unique&lt;JSON::Object&gt;()}; auto &amp;root = json-&gt;cast&lt;JSON::Object&gt;(); root[&quot;123&quot;] = 456; root[&quot;

&quot;] = &quot;hello&quot;; root[&quot; 	&quot;] = 114.514; root[&quot;true&quot;] = false; root[&quot;null&quot;] = nullptr; root[&quot;array&quot;] = JSON::Array::makeArray(1, true, 11514.1919, -2147483648, &quot;miao&quot;, nullptr); root[&quot;array2&quot;] = JSON::Array::makeArray( 1, JSON::Array::makeArray(1, JSON::Array::makeArray(4), JSON::Array::makeArray(JSON::Array::makeArray(5)), JSON::Array::makeArray(1)), 4, JSON::Array::makeArray()); std::cout &lt;&lt; json-&gt;dump(); 输出（美化后） { &quot;array2&quot;: [1, [1, [4], [[5]], [1]], 4, []], &quot;array&quot;: [1, true, 11514.1919, -2147483648, &quot;miao&quot;, null], &quot;null&quot;: null, &quot; 	&quot;: 114.514, &quot;true&quot;: false, &quot;

&quot;: &quot;hello&quot;, &quot;123&quot;: 456 } 真是简简又单单啊 完整代码 ¶ https://github.com/Lhcfl/cpp-json-learn/blob/main/cppjson.h 684 行，实现了一个还可以的玩具 C++ 解析库，并且能 90% 情况下和 JavaScript 的 JSON 解析保持抛出一致的异常（） 所以 ¶ 看到这坨东西的时候 ⬇️ 还写 C++ 吗.png 还写吗 template &lt;typename IntN&gt; requires std::numeric_limits&lt;IntN&gt;::is_integer explicit JSON(IntN integer) : _uptr(std::make_unique&lt;Number&gt;(static_cast&lt;int64_t&gt;(integer))) {} template &lt;typename IntN&gt; requires std::numeric_limits&lt;IntN&gt;::is_integer inline JSON &amp;operator=(IntN integer) { // 用看上去是 integer 的任何类型赋值 _uptr = std::make_unique&lt;Number&gt;(static_cast&lt;int64_t&gt;(integer)); return *this; } 别用 C++
